 1→import { useMemo } from 'react';
 2→import FloorplanWorkspace from '@floorplan';
 3→import { createWall, createDoor, createWindow, createFloor } from '@/domain/models';
 4→import { generateId } from '@/domain/ids';
 5→import { CURRENT_PROJECT_VERSION } from '@/domain/projectVersion';
 6→
 7→function buildDemoProject() {
 8→  const projectId = generateId('proj');
 9→  const floorId = generateId('floor');
10→
11→  // Create 4 walls forming a 6000x4000mm rectangle
12→  const wall1 = createWall({ x: 0, y: 0 }, { x: 6000, y: 0 });       // top
13→  const wall2 = createWall({ x: 6000, y: 0 }, { x: 6000, y: 4000 }); // right
14→  const wall3 = createWall({ x: 6000, y: 4000 }, { x: 0, y: 4000 }); // bottom
15→  const wall4 = createWall({ x: 0, y: 4000 }, { x: 0, y: 0 });       // left
16→
17→  // Place a door on wall 3 (bottom) at offset ~2000
18→  const door = createDoor(wall3.id, 2000);
19→
20→  // Place a window on wall 2 (right) at offset ~1500
21→  const win = createWindow(wall2.id, 1500);
22→
23→  // Build a floor manually based on the createFloor structure
24→  const floor = createFloor('Ground Floor', 0, { elevation: 0, floorToFloorHeight: 3000 });
25→  floor.id = floorId;
26→  floor.walls = [wall1, wall2, wall3, wall4];
27→  floor.doors = [door];
28→  floor.windows = [win];
29→
30→  return {
31→    id: projectId,
32→    name: 'Playground Demo',
33→    address: '',
34→    documentDefaults: {
35→      drawnBy: '',
36→      checkedBy: '',
37→    },
38→    createdAt: new Date().toISOString(),
39→    updatedAt: new Date().toISOString(),
40→    floors: [floor],
41→    roofSystem: null,
42→    trussSystems: [],
43→    sheets: [],
